code.javascript:
function dfs(node) {
  if (!node) return;
  dfs(node.left);
  dfs(node.right);
}

code.java:
void dfs(Node node) {
  if (node == null) return;
  dfs(node.left);
  dfs(node.right);
}

code.cpp:
void dfs(Node* node) {
  if (!node) return;
  dfs(node->left);
  dfs(node->right);
}

