code.javascript:
const q = [root];
while (q.length) {
  const node = q.shift();
  if (node.left) q.push(node.left);
  if (node.right) q.push(node.right);
}

code.java:
Queue<Node> q = new LinkedList<>();
q.offer(root);
while (!q.isEmpty()) {
  Node node = q.poll();
  if (node.left != null) q.offer(node.left);
  if (node.right != null) q.offer(node.right);
}

